import requests

def solve(arg1: dict) -> dict:
    if 'challengeId' in arg1:
        challenge_id = arg1['challengeId']
        # Fetch scorecard details
        try:
            response = requests.get(f'https://api.example.com/scorecards/{challenge_id}')
            if response.status_code == 200:
                return response.json()
            elif response.status_code == 404:
                return {'error': 'Scorecard not found'}
        except Exception as e:
            return {'error': str(e)}

    if 'appealData' in arg1:
        # Create appeal
        appeal_data = arg1['appealData']
        try:
            response = requests.post('https://api.example.com/appeals', json=appeal_data)
            if response.status_code == 201:
                return response.json()
            else:
                return {'error': 'Invalid appeal data'}
        except Exception as e:
            return {'error': str(e)}

    if 'updateData' in arg1:
        # Update appeal
        update_data = arg1['updateData']
        try:
            response = requests.put(f'https://api.example.com/appeals/{update_data["appealId"]}', json=update_data)
            if response.status_code == 200:
                return response.json()
        except Exception as e:
            return {'error': str(e)}

    return None
